from solution import solve

def test_tie_breaking_order():
    assert solve({'cook': ['eat'], 'shop': ['cook'], 'clean': []}) == ['clean', 'shop', 'cook', 'eat']

def test_cycle_returns_empty():
    assert solve({'a': ['b'], 'b': ['a']}) == []
